# Checkers Game Implementation

class Checkers:
    def __init__(self):
        self.board = self.create_initial_board()
        self.current_player = 'white'
        self.game_over = False

    def create_initial_board(self):
        board = [[''] * 8 for _ in range(8)]
        for row in range(3, 5):
            for col in range(row % 2, 8, 2):
                board[row][col] = 'white'
        for row in range(5, 7):
            for col in range((row + 1) % 2, 8, 2):
                board[row][col] = 'black'
        return board

    def print_board(self):
        for row in self.board:
            print(' '.join(row))

    def move_piece(self, from_pos, to_pos):
        from_row = ord(from_pos[0]) - 65
        from_col = int(from_pos[1:]) - 1
        to_row = ord(to_pos[0]) - 65
        to_col = int(to_pos[1:]) - 1

        piece = self.board[from_row][from_col]
        if not piece:
            return False

        if self.current_player == 'white' and piece != 'white':
            return False
        elif self.current_player == 'black' and piece != 'black':
            return False

        if (abs(from_row - to_row), abs(from_col - to_col)) not in [(1, 1), (2, 2)]:
            return False

        if (from_row - to_row) == 2 or (from_row - to_row) == -2:
            if not self.board[(from_row + to_row) // 2][(from_col + to_col) // 2].endswith('k'):
                return False

        self.board[from_row][from_col] = ''
        self.board[to_row][to_col] = piece + 'k' if abs(from_row - to_row) == 2 else piece
        return True

    def check_winner(self):
        white_count = sum(row.count('white') for row in self.board)
        black_count = sum(row.count('black') for row in self.board)

        if not any(row.count('whitek') for row in self.board) or not any(row.count('blackk') for row in self.board):
            return self.current_player.capitalize() if white_count == 0 else 'Black' if black_count == 0 else 'Draw'

    def main_loop(self):
        while not self.game_over:
            self.print_board()
            from_pos = input(f'{self.current_player.capitalize()}'s turn. Enter the move (e.g., A1-A2): ').upper().replace(' ', '')
            to_pos = input('Enter the destination position: ').upper().replace(' ', '')
            if self.move_piece(from_pos, to_pos):
                if self.check_winner():
                    print(self.check_winner() + ' wins!')
                    self.game_over = True
                else:
                    self.switch_player()
            else:
                print('Invalid move. Try again.')

if __name__ == '__main__':
    game = Checkers()
    game.main_loop()"}}
